            url uri('../repo')
        }
    }
    dependencies{
        classpath 'com.stan.auto.plugin:autoaddversioncode:1.0.13'
    }
}

versionFile{
   desFile  = 'gradle'
}

android {
    ......
}
```
以上示例会在Gradle projects 包目录下的和 upload 同级的 Other下生成 hello task，点击hello运行，会自增 :app 下的 build.gralde中的versionCode，插件功能完成。

